    if (!selectedEndpoint) return;
    if (!validateClientCode(requestBody)) return;

    setLoading(true);
    try {
      let response;
      const clientCode = userInfo.ClientCode;

      switch (selectedEndpoint.endpoint) {
        case 'SaveRFIDTransactionDetails':
        case 'UpdateRFIDTransactionDetails':
          // These endpoints expect an array of items
          response = await axios.post(
            `${selectedEndpoint.baseUrl}/${selectedEndpoint.endpoint}`,
            [requestBody]
          );
          break;

        case 'GetRFIDTransactionDetails':
          // Use the rfidService for consistent error handling
          response = await rfidService.getRFIDTransactions(clientCode);
          break;

        case 'DeleteLabelledStockItems':
          // Use the rfidService for consistent error handling
          response = await rfidService.deleteLabelledStock(clientCode, requestBody.ItemCodes);
          break;

        case 'GetAllRFIDDetails':
        case 'DeleteRFIDByClientAndDevice':
          // These endpoints expect a single object
          response = await axios.post(
            `${selectedEndpoint.baseUrl}/${selectedEndpoint.endpoint}`,
            requestBody
          );
          break;

        default:
          throw new Error('Unknown endpoint');
      }

      setResponse(response.data);
      setResponseBody(response.data);
      toast.success('API call successful!');
